import React from 'react';
import ParamHeader from './ParamHeader';

function HeartsCounter({ hearts, onHeartsChange, paramIcons, onIconClick, buttonRefs }) {
  return (
    <div className="bg-white/60 backdrop-blur-sm rounded-2xl p-4 shadow-lg">
      <div className="flex items-center justify-between">
        <ParamHeader
          paramKey="hearts"
          label="爱心数量"
          iconColor="text-red-400 fill-red-400"
          onIconClick={onIconClick}
          buttonRef={(el) => buttonRefs.current.hearts = el}
        />
        <div className="flex items-center gap-2">
          <button
            onClick={() => onHeartsChange(Math.max(0, hearts - 1))}
            className="w-8 h-8 rounded-full bg-gradient-to-r from-pink-300 to-red-300 text-white font-bold hover:scale-110 transition-transform shadow-md"
          >
            −
          </button>
          <span className="text-lg font-bold text-pink-500 w-8 text-center">{hearts}</span>
          <button
            onClick={() => onHeartsChange(Math.min(10, hearts + 1))}
            className="w-8 h-8 rounded-full bg-gradient-to-r from-pink-400 to-red-400 text-white font-bold hover:scale-110 transition-transform shadow-md"
          >
            +
          </button>
        </div>
      </div>
    </div>
  );
}

export default HeartsCounter;
